125→// IntegrationSearch_MetadataDrivenAllFields generates a single query that
126→// combines every searchable field at once. This is the most extreme stress
127→// test for placeholder numbering and SQL generation.
128→func TestIntegrationSearch_MetadataDrivenAllFields(t *testing.T) {
129→	pool := integrationPool(t)
130→	ctx := context.Background()
131→	reg := search.NewRegistry()
132→
133→	var filters []search.FilterInput
134→	for _, desc := range searchableDescriptors(reg) {
135→		f := filterFromDescriptor(t, desc)
136→		if f == nil {
137→			continue
138→		}
139→		filters = append(filters, search.FilterInput{Field: desc.Name, Value: f})
140→	}
141→
142→	if len(filters) == 0 {
143→		t.Skip("no filters generated")
144→	}
145→
146→	req := search.SearchRequest{
147→		Filters: filters,
148→		Limit:   5,
149→	}
150→
151→	if errs := search.ValidateRequest(reg, req, true); len(errs) != 0 {
152→		t.Fatalf("validation errors: %v", errs)
153→	}
154→
155→	sql, args, err := search.BuildQuery(reg, req)
156→	if err != nil {
157→		t.Fatalf("BuildQuery: %v", err)
158→	}
159→	assertQueryExecutes(t, ctx, pool, sql, args)
160→}
