166→// integrationPool returns a pgxpool connected to the dev database. The test is
167→// skipped when running in short mode or when DATABASE_URL is unset.
168→func integrationPool(t *testing.T) *pgxpool.Pool {
169→	t.Helper()
170→	if testing.Short() {
171→		t.Skip("integration test")
172→	}
173→	dsn := os.Getenv("DATABASE_URL")
174→	if dsn == "" {
175→		t.Skip("DATABASE_URL not set")
176→	}
177→	pool, err := pgxpool.New(context.Background(), dsn)
178→	if err != nil {
179→		t.Fatalf("connect: %v", err)
180→	}
181→	t.Cleanup(pool.Close)
182→	return pool
183→}
184→
185→// sortedFields returns all registry fields sorted by name for deterministic
186→// iteration order.
187→func sortedFields(reg *search.Registry) []search.Field {
188→	fields := reg.All()
189→	sort.Slice(fields, func(i, j int) bool {
190→		return fields[i].Name() < fields[j].Name()
191→	})
192→	return fields
193→}
194→
195→// searchableDescriptors returns descriptors for all searchable fields, sorted
196→// by name.
197→func searchableDescriptors(reg *search.Registry) []search.FieldDescriptor {
198→	var out []search.FieldDescriptor
199→	for _, f := range sortedFields(reg) {
200→		d := f.Descriptor()
201→		if d.Searchability == search.SearchabilitySearchable {
202→			out = append(out, d)
203→		}
204→	}
205→	return out
206→}
207→
208→// filterFromDescriptor builds a minimal valid JSON filter from the field's
209→// published metadata. The algorithm is deterministic — it always picks the
210→// first option, the midpoint of bounds, or fixed sentinel values.
211→func filterFromDescriptor(t *testing.T, desc search.FieldDescriptor) json.RawMessage {
212→	t.Helper()
213→	switch desc.Kind {
214→	case search.KindFullText:
215→		return mustMarshal(t, search.FullTextFilter{Query: "university"})
216→
217→	case search.KindSubstring:
218→		return mustMarshal(t, search.SubstringFilter{Value: "a"})
219→
220→	case search.KindExactString:
221→		return mustMarshal(t, search.ExactStringFilter{Value: "100000"})
222→
223→	case search.KindExactNumeric:
224→		return mustMarshal(t, search.ExactNumericFilter{Value: 1})
225→
226→	case search.KindNumericRange:
227→		return numericRangeFromBounds(t, desc.Bounds)
228→
229→	case search.KindSingleEnum:
230→		if len(desc.Options) == 0 {
231→			return nil
232→		}
233→		return mustMarshal(t, search.SingleEnumFilter{Value: desc.Options[0].Value})
234→
235→	case search.KindMultiEnum:
236→		if len(desc.Options) > 0 {
237→			return mustMarshal(t, search.MultiEnumFilter{Values: []string{desc.Options[0].Value}})
238→		}
239→		// Open-ended field (e.g. fields_of_study): use a plausible sentinel.
240→		return mustMarshal(t, search.MultiEnumFilter{Values: []string{"52.0101"}})
241→
242→	case search.KindGeo:
243→		// Deterministic point: roughly centre of continental US.
244→		return mustMarshal(t, search.GeoFilterInput{
245→			Kind: search.GeoFilterKindRadius,
246→			Radius: &search.GeoRadiusFilter{
247→				Lat: 39.8283, Lng: -98.5795, RadiusKm: 100,
248→			},
249→		})
250→
251→	default:
252→		return nil
253→	}
254→}
255→
256→// numericRangeFromBounds generates a NumericRangeFilter from the field's hard
257→// bounds. When bounds are nil it uses generous defaults.
258→func numericRangeFromBounds(t *testing.T, bounds *search.NumericBounds) json.RawMessage {
259→	t.Helper()
260→	min := 0.0
261→	max := 1000000.0
262→
263→	if bounds != nil {
264→		if bounds.Min != nil {
265→			min = *bounds.Min
266→		}
267→		if bounds.Max != nil {
268→			max = *bounds.Max
269→		}
270→	}
271→
272→	// Use the full range so we get some results.
273→	return mustMarshal(t, search.NumericRangeFilter{Min: &min, Max: &max})
274→}
