33→func TestValidateRequest(t *testing.T) {
34→	t.Parallel()
35→	reg := search.NewRegistry()
36→
37→	t.Run("unknown field", func(t *testing.T) {
38→		req := search.SearchRequest{
39→			Filters: []search.FilterInput{
40→				{Field: "does_not_exist", Value: mustJSON(map[string]any{"value": "x"})},
41→			},
42→		}
43→		errs := search.ValidateRequest(reg, req, true)
44→		if len(errs) != 1 {
45→			t.Fatalf("expected 1 error, got %d", len(errs))
46→		}
47→		if errs[0].Field != "does_not_exist" {
48→			t.Errorf("expected field 'does_not_exist', got %q", errs[0].Field)
49→		}
50→		if errs[0].Message != "unknown field" {
51→			t.Errorf("unexpected message: %q", errs[0].Message)
52→		}
53→	})
54→
55→	t.Run("bad enum value for state", func(t *testing.T) {
56→		req := search.SearchRequest{
57→			Filters: []search.FilterInput{
58→				{Field: "state", Value: mustJSON(search.MultiEnumFilter{Values: []string{"XX"}})},
59→			},
60→		}
61→		errs := search.ValidateRequest(reg, req, true)
62→		if len(errs) != 1 {
63→			t.Fatalf("expected 1 error, got %d", len(errs))
64→		}
65→		if !strings.Contains(errs[0].Message, "not in allowed options") {
66→			t.Errorf("unexpected message: %q", errs[0].Message)
67→		}
68→	})
69→
70→	t.Run("multi enum bad value", func(t *testing.T) {
71→		req := search.SearchRequest{
72→			Filters: []search.FilterInput{
73→				{Field: "application_platforms", Value: mustJSON(search.MultiEnumFilter{Values: []string{"Not A Real App"}})},
74→			},
75→		}
76→		errs := search.ValidateRequest(reg, req, true)
77→		if len(errs) != 1 {
78→			t.Fatalf("expected 1 error, got %d: %v", len(errs), errs)
